'use client';

import { useEffect, useState } from 'react';
import { useParams, useRouter } from 'next/navigation';
import Image from 'next/image';
import { Button } from '@/components/ui/button';
import { ArrowLeft, ImageIcon } from 'lucide-react';
import { Navigation } from '@/components/navigation';

interface Character {
  id: string;
  title: string;
  description: string | null;
  image_url: string | null;
  thumbnail_url: string | null;
  created_at: string;
}

export default function CharacterDetailPage() {
  const params = useParams();
  const router = useRouter();
  const id = params?.id as string;

  const [character, setCharacter] = useState<Character | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    if (!id) return;
    
    // Fetch individual character
    const fetchCharacter = async () => {
      try {
        const res = await fetch(`/api/characters/${id}`);
        if (res.ok) {
          const data = await res.json();
          setCharacter(data);
        }
      } catch (error) {
        console.error('Failed to fetch character:', error);
      } finally {
        setIsLoading(false);
      }
    };

    fetchCharacter();
  }, [id]);

  if (isLoading) {
    return (
      <div className="min-h-screen bg-transparent">
        <Navigation />
        <main className="w-full md:w-[80%] mx-auto py-8">
          <div className="animate-pulse bg-muted h-[600px] rounded-lg"></div>
        </main>
      </div>
    );
  }

  if (!character) {
    return (
      <div className="min-h-screen bg-transparent">
        <Navigation />
        <main className="w-full md:w-[80%] mx-auto py-8 text-center text-foreground">
          <p>캐릭터를 찾을 수 없습니다.</p>
          <Button onClick={() => router.back()} className="mt-4">
            뒤로 가기
          </Button>
        </main>
      </div>
    );
  }

  return (
    <div className="h-screen w-full flex flex-col bg-transparent overflow-hidden">
      <Navigation />
      <main className="flex-1 w-full flex flex-col md:flex-row relative">
        
        {/* Left: Image (Split screen 50%) */}
        <div className="relative w-full md:w-1/2 h-[50vh] md:h-full bg-transparent flex items-center justify-center p-4">
          {/* Back Button Overlay top-left of image */}
          <button 
            onClick={() => router.back()}
            aria-label="뒤로 가기"
            className="absolute top-8 left-8 z-10 w-12 h-12 flex flex-col items-center justify-center text-white bg-transparent outline-none cursor-pointer group"
          >
            <div className="absolute inset-0 bg-white/10 rounded-full blur-[2px] transition-all group-hover:bg-white/30"></div>
            <ArrowLeft className="h-8 w-8 relative z-20 drop-shadow-md" />
          </button>

          {character.image_url ? (
            <Image 
              src={character.image_url} 
              alt={character.title}
              fill
              className="object-contain p-4"
            />
          ) : (
            <ImageIcon className="w-20 h-20 text-muted-foreground" />
          )}
        </div>

        {/* Right: Info */}
        <div className="w-full md:w-1/2 h-full bg-card/60 backdrop-blur-sm p-8 lg:p-16 flex flex-col justify-center overflow-y-auto border-l border-white/10">
          <h1 className="text-4xl md:text-5xl font-bold mb-8 text-foreground">{character.title}</h1>
          <div className="prose prose-sm md:prose-base max-w-none text-foreground/90 whitespace-pre-wrap leading-relaxed">
            {character.description || '설명이 없습니다.'}
          </div>
          
          <div className="mt-8 md:mt-auto pt-10 text-sm text-muted-foreground border-t border-border/50">
            등록일: {new Date(character.created_at).toLocaleDateString()}
          </div>
        </div>

      </main>
    </div>
  );
}
